column6:
"IF (GETTOKEN.HTTP_CODE==200) && ISEQUAL(GETTOKEN.VALUE.token_type,'Bearer') THEN
    X.201 := 1;
    $.GPARAM.TOKENTYPE := GETTOKEN.VALUE.token_type;
    $.GPARAM.EXPIRESIN := GETTOKEN.VALUE.expires_in;
    $.GPARAM.ACCESSTOKEN := GETTOKEN.VALUE.access_token;
    $.GPARAM.EXPIRESDATE := ( ( $.GPARAM.EXPIRESIN * 5 ) / 6 ) + $.SYS.TIME;
    GETTEAMID.F := 1;
ELSE
    $.GPARAM.EXPIRESDATE := 60 + $.SYS.TIME;
    X.210 := GETTOKEN.VALUE.error;
    X.210 := CONCAT('Token Error: ',X.210);
    X.201 := 0;
    MSG_TIME := $.SYS.TIME;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETTOKEN.URL);
    DEBUG(GETTOKEN.HTTP_CODE);
    DEBUG(GETTOKEN.HTTP_DATA);
ENDIF;
GETTOKEN.F := 0;"

"IF GETTEAMID.HTTP_CODE == 200 THEN
    X.202 := 1;
    X.3 := GETTEAMID.VALUE.value[0].id;
ELSE
    X.202 := 0;
    X.210 := GETTEAMID.VALUE.error.code;
    X.210 := CONCAT('Team ID Error: ',X.210);
    MSG_TIME := $.SYS.TIME;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETTEAMID.URL);
    DEBUG(GETTEAMID.HTTP_CODE);
    DEBUG(GETTEAMID.HTTP_DATA);
ENDIF;
GETUSERID.F := 0;"

"IF GETSHIFTS.HTTP_CODE == 200 THEN
    X.203 := 1;
    X.5 := GETSHIFTS.ARRAY.LEN.value;
    $.GPARAM.EXPIRESDATE_SHIFTS := 60 * 60 + $.SYS.TIME;
ELSE
    X.203 := 0;
    $.GPARAM.EXPIRESDATE_SHIFTS := 60 * 5 + $.SYS.TIME;
    X.210 := GETSHIFTS.VALUE.error.code;
    X.210 := CONCAT('Shifts Error: ',X.210);
    MSG_TIME := $.SYS.TIME;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETSHIFTS.URL);
    DEBUG(GETSHIFTS.HTTP_CODE);
    DEBUG(GETSHIFTS.HTTP_DATA);
ENDIF;
$.GPARAM.SHIFTSDATA := GETSHIFTS.HTTP_DATA;
GETSHIFTS.F := 0;"

"IF GETUSERID.HTTP_CODE == 200 THEN
    X.204 := 1;
    X.1 := GETUSERID.VALUE.value[0].id;
ELSE
    X.204 := 0;
    X.210 := GETUSERID.VALUE.error.code;
    X.210 := CONCAT('User ID Error: ',X.210);
    MSG_TIME := $.SYS.TIME;
ENDIF;
IF ISEQUAL($.GPARAM.VERBOSE,'ON') THEN
    DEBUG(GETUSERID.URL);
    DEBUG(GETUSERID.HTTP_CODE);
    DEBUG(GETUSERID.HTTP_DATA);
ENDIF;
GETUSERID.F := 0;"

column10:
"X.180 := $.GPARAM.EXPIRESDATE - $.SYS.TIME;
IF X.180 <= 0 THEN X.180 :=0; ENDIF;
IF ISEQUAL($.PARAM.SLAVE,$.GPARAM.SLAVE) && X.195 && (X.180 == 0) THEN 
    GETTOKEN.F :=1;
    DEBUG_INFO := 'Token Request'; DEBUG(DEBUG_INFO);
ENDIF;"

"X.181 := $.GPARAM.EXPIRESDATE_SHIFTS - $.SYS.TIME;
IF X.181 <= 0 THEN X.181 :=0; ENDIF;
IF ( LEN($.GPARAM.ACCESSTOKEN) >0 ) && ( LEN(X.3) > 0 ) && ISEQUAL($.PARAM.SLAVE,$.GPARAM.SLAVE) && X.195 && (X.181 == 0) THEN 
    GETSHIFTS.F := 1;
    REF_TIME := $.SYS.TIME;
    YEAR := DATEYEAR(REF_TIME);
    MONTH := DATEMONTH(REF_TIME);
    DAY := DATEDAY(REF_TIME);
    WINDOW_START := TIMEFROM_DATE(YEAR,MONTH,DAY,02,00,00,0);
    WINDOW_END := TIMEFROM_DATE(YEAR,MONTH,DAY,22,00,00,0);
    WINDOW_START_ISO := ISO8601(WINDOW_START,0);
    WINDOW_END_ISO := ISO8601(WINDOW_END,0);
    DEBUG(WINDOW_START_ISO,WINDOW_END_ISO);
    FILTER_1 := CONCAT('draftShift/startDateTime ge ',WINDOW_START_ISO);
    FILTER_2 := CONCAT('draftShift/endDateTime le ',WINDOW_END_ISO);
    FILTER_GET_SHIFTS := CONCAT(FILTER_1,' and ',FILTER_2);
    DEBUG_INFO := 'Shifts Request'; DEBUG(DEBUG_INFO);
ENDIF;"

"X.182 := EXPIRESDATE_ID - $.SYS.TIME;
IF X.182 <= 0 THEN X.182 :=0; ENDIF;
CONDITION := ( LEN($.GPARAM.ACCESSTOKEN) >0 ) && X.195 && (X.182 == 0);
IF CONDITION && ( LEN(X.2) > 0) && (ISEQUAL($.PARAM.SLAVE,$.GPARAM.SLAVE) THEN 
    GETTEAMID.F := 1;
    DEBUG_INFO := 'Team ID Request'; DEBUG(DEBUG_INFO);
    EXPIRESDATE_ID := DEC($.SYS.TIME, 5000) * 5000 + 5000;
ENDIF;
IF CONDITION && ( LEN(X.0) > 0) && X.195 THEN
    GETUSERID.F := 1;    
    DEBUG_INFO := 'User ID Request'; DEBUG(DEBUG_INFO);
    EXPIRESDATE_ID := DEC($.SYS.TIME, 5000) * 5000 + 5000;
ENDIF;"

"X.183 := EXPIRESDATE_PCALC - $.SYS.TIME;
IF X.183 <= 0 THEN X.183 := 0; ENDIF;
DO_RECALC := ( X.183 == 0 );
IF DO_RECALC THEN
    DEBUG_INFO := 'Check Presence Request';
    EXPIRESDATE_PCALC := DEC($.SYS.TIME,120) * 120 + 150;
ENDIF;
IF DO_RECALC THEN
    NOW_UNIX := $.SYS.TIME;
    YEAR_T := DATEYEAR(NOW_UNIX);
    MONTH_T := DATEMONTH(NOW_UNIX);
    DAY_T := DATEDAY(NOW_UNIX);
    WEEKDAY_T := DATEWDAY(NOW_UNIX);
    RANGE_TODAY := '';
ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 1 ) THEN RANGE_TODAY := X.31; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 2 ) THEN RANGE_TODAY := X.32; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 3 ) THEN RANGE_TODAY := X.33; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 4 ) THEN RANGE_TODAY := X.34; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 5 ) THEN RANGE_TODAY := X.35; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 6 ) THEN RANGE_TODAY := X.36; ENDIF;
IF DO_RECALC && ( WEEKDAY_T == 7 ) THEN RANGE_TODAY := X.37; ENDIF;
IF DO_RECALC THEN
    RP_FOUND := 0;
ENDIF;
IF DO_RECALC && ( LEN(RANGE_TODAY) >= 5 ) THEN
    SHH := STRING_TO_NUMBER(RANGE_TODAY,0,2,INT8);
    SMM := STRING_TO_NUMBER(RANGE_TODAY,3,2,INT8);
    EHH := STRING_TO_NUMBER(RANGE_TODAY,6,2,INT8);
    EMM := STRING_TO_NUMBER(RANGE_TODAY,9,2,INT8);
    RP_START := TIMEFROM_DATE(YEAR_T,MONTH_T,DAY_T,SHH,SMM,0,0);
    RP_END := TIMEFROM_DATE(YEAR_T,MONTH_T,DAY_T,EHH,EMM,0,0);
    RP_FOUND := 1;
ENDIF;

IF DO_RECALC && ( LEN(X.1) == 0 ) THEN
    X.10 := 'ERR: NO_USER_ID';
    X.208 := 1;
ELSE
    X.208 := 0;   
ENDIF;

IF DO_RECALC THEN
    AS_START_ISO_UTC := JSONGETVALUEFROMARRAY($.GPARAM.SHIFTSDATA,'value','draftShift.startDateTime',AND,STRING,'userId','==',X.1);
    AS_END_ISO_UTC := JSONGETVALUEFROMARRAY($.GPARAM.SHIFTSDATA,'value','draftShift.endDateTime',AND,STRING,'userId','==',X.1);
    X.6 := AS_START_ISO_UTC;
    X.7 := AS_END_ISO_UTC; 
    X.8 := JSONGETVALUEFROMARRAY($.GPARAM.SHIFTSDATA,'value','draftShift.theme',AND,STRING,'userId','==',X.1);
    X.9 := JSONGETVALUEFROMARRAY($.GPARAM.SHIFTSDATA,'value','draftShift.notes',AND,STRING,'userId','==',X.1);
    X.10 := CONCAT(X.8,' | ',X.9);
    X.10 := SUBSTRING(X.10,0,22);
    AS_START := TIMEFROMISO8601(AS_START_ISO_UTC);
    AS_END := TIMEFROMISO8601(AS_END_ISO_UTC);
    AS_TODAY := ( YEAR_T == DATEYEAR(AS_START) ) && ( MONTH_T == DATEMONTH(AS_START) ) && ( DAY_T == DATEDAY(AS_START) );
    AS_FOUND := ( LEN(AS_START_ISO_UTC) > 0 ) && AS_TODAY;
    AS_DURATION := AS_END - AS_START;
    MIN_AP := $.GPARAM.DAYSHIFT * 60 * 60;
    MIN_AP := ROUND(MIN_AP);
    MAX_AP := 11 * 60 * 60;
    AS_DEFINES_RP := ( MIN_AP <= AS_DURATION ) && ( AS_DURATION <= MAX_AP );
ENDIF;

IF DO_RECALC && AS_FOUND && AS_DEFINES_RP THEN
    RP_FOUND := 1;
    RP_START := AS_START;
    RP_END := AS_END;
ENDIF;

X.20 := RP_FOUND && ( RP_START <= $.SYS.TIME ) && ( $.SYS.TIME < RP_END ) ;

IF DO_RECALC && RP_FOUND THEN
    RP_START_ISO := ISO8601(RP_START,0);
    RP_END_ISO   := ISO8601(RP_END,0);
    RP_START_HM := SUBSTRING(RP_START_ISO,11,5);
    RP_END_HM := SUBSTRING(RP_END_ISO,11,5);
    X.30 := CONCAT(RP_START_HM,' - ',RP_END_HM);
ELSE IF DO_RECALC THEN
    X.30 := '---';   
ENDIF;

IF DO_RECALC && RP_FOUND && AS_FOUND && AS_DEFINES_RP THEN
    X.30 := CONCAT('[S] ',X.30);
ENDIF;


IF DO_RECALC && ( AS_FOUND == 0 ) THEN
    X.10 := '---';
ENDIF;

AS_NOW := AS_FOUND && (AS_START <= $.SYS.TIME) && ($.SYS.TIME < AS_END);
IF AS_NOW THEN
    X.21 := 0;
ELSE
    X.21 := X.20;
ENDIF;


IF DO_RECALC && AS_FOUND THEN 
    AS_START_ISO := ISO8601(AS_START,0);
    AS_END_ISO   := ISO8601(AS_END,0);
    AS_START_HM := SUBSTRING(AS_START_ISO,11,5);
    AS_END_HM   := SUBSTRING(AS_END_ISO,11,5);
    X.40 := CONCAT(AS_START_HM,' - ',AS_END_HM);
ELSE IF DO_RECALC THEN
    X.40 := '---';    
ENDIF;

IF DO_RECALC THEN 
    ARRIVE_LEAD := X.38 * 60 * 60;
    DEPARTURE_LEAD := X.39 * 60 * 60;
    ARRIVE_LEAD := ROUND(ARRIVE_LEAD);
    DEPARTURE_LEAD := ROUND(DEPARTURE_LEAD);
    HVAC_RESULT  := 1;     CMT := '1 = valid, 0 = no heating, -1 = invalid input';
ENDIF;


IF DO_RECALC && ( RP_FOUND == 0 ) THEN
    HVAC_RESULT := 0;
    CMT := 'No presence interval -> no heating.';
    X.41 := 'NO_REG_PRES';
ELSE IF DO_RECALC && ( RP_START >= RP_END ) THEN
    HVAC_RESULT := -1;
    CMT := 'Invalid presence interval (RP_START >= RP_END).'; DEBUG(CMT);
    X.41 := 'INV_REG_PRES';
ENDIF;


IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( AS_FOUND == 0) THEN
    EFF_EARLIEST := RP_START;
    EFF_LATEST   := RP_END;
ELSE IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( ( AS_END <= RP_START ) || ( AS_START >= RP_END ) ) THEN
    CMT := 'absence entirely outside presence';
    EFF_EARLIEST := RP_START;
    EFF_LATEST   := RP_END;
ELSE IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( AS_START <= RP_START ) && ( AS_END >= RP_END ) THEN
    CMT := 'absence covers whole presence -> no heating.';
    X.41 := 'ABS_COV_PRES';
    HVAC_RESULT := 0;
ELSE IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( AS_START <= RP_START ) && ( AS_END < RP_END ) THEN
    CMT := 'absence cuts left side';
    EFF_EARLIEST := AS_END;
    EFF_LATEST   := RP_END;
ELSE IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( AS_START > RP_START ) && ( AS_END >= RP_END ) THEN
    CMT := 'absence cuts right side';
    EFF_EARLIEST := RP_START;
    EFF_LATEST   := AS_START;
ELSE IF DO_RECALC && ( HVAC_RESULT == 1 ) THEN
    CMT := 'none of the above matched -> absence inside presence';
    EFF_EARLIEST := RP_START;
    EFF_LATEST   := RP_END;
ENDIF;

IF DO_RECALC && ( HVAC_RESULT == 1 ) THEN
    HVAC_START := EFF_EARLIEST - ARRIVE_LEAD;
    HVAC_END   := EFF_LATEST - DEPARTURE_LEAD;
ENDIF;

IF DO_RECALC && ( HVAC_RESULT == 1 ) && ( HVAC_START >= HVAC_END ) THEN
    HVAC_RESULT := 0;
    CMT := 'Leadtimes remove heating interval.';
    X.41 := 'LEAD_IS_LONGER';
ENDIF;

X.22 :=  ( HVAC_RESULT == 1 ) && (HVAC_START <= $.SYS.TIME) && ($.SYS.TIME < HVAC_END);
IO.1.0 := X.22;
IF DO_RECALC && ( HVAC_RESULT == 1 ) THEN
    HVAC_START_ISO := ISO8601(HVAC_START,0);
    HVAC_END_ISO   := ISO8601(HVAC_END,0);
    HVAC_START_HM := SUBSTRING(HVAC_START_ISO,11,5);
    HVAC_END_HM := SUBSTRING(HVAC_END_ISO,11,5);
    X.41 := CONCAT(HVAC_START_HM,' - ',HVAC_END_HM);
ENDIF;

X.25 := X.21 + ( X.22 * 2 );
X.222 := X.22 * 40;
X.220 := X.20 * 40;
X.221 := X.21 * 40;"
